INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Unified notification inbox$q$, $q$A pre-built, customizable in-app inbox component that shows a user's notification history across channels.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Multi-channel delivery$q$, $q$Send the same event to email, mobile push, web push, Slack, Teams, and SMS from a single API call.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Preference center$q$, $q$Lets end users choose which notification types and channels they want to receive.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Notification templates$q$, $q$Reusable templates with variables so engineering does not have to hardcode copy for every event.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Real-time delivery$q$, $q$Websocket-based updates push new notifications into the inbox instantly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Batching and digests$q$, $q$Groups related notifications to reduce noise instead of sending one alert per event.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Analytics$q$, $q$Tracks delivery, open, and click rates per channel and notification type.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Developer SDKs$q$, $q$Official libraries for React, React Native, Node.js, Ruby, Python, and Go plus a REST API and webhooks.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Generous free tier covering 1,000 deliveries per month with full feature access$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Pre-built inbox UI saves significant frontend development time$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Single API for multiple notification channels instead of integrating each provider separately$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Per-user preference management built in rather than needing to be custom-built$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Strong developer documentation and multiple official SDKs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Pricing jumps sharply from the free tier to the 249 dollar per month Startup plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Primarily useful for product/transactional notifications, not a substitute for marketing email tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Smaller company than larger notification competitors, which may affect long-term roadmap certainty$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Advanced features like SSO are locked behind custom Enterprise pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Requires engineering integration effort rather than being usable by non-technical marketers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$What is MagicBell used for$q$, $q$MagicBell is used by software teams to add in-app, email, push, SMS, and Slack notifications to their product without building the delivery infrastructure themselves.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Is MagicBell free to use$q$, $q$Yes, MagicBell offers a free Builder plan with 1,000 notification deliveries per month and access to all channels and integrations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Who founded MagicBell$q$, $q$MagicBell was founded in 2020 by Hana Mohan and Josue Montano, who previously worked together at SupportBee, and the company went through Y Combinator.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Does MagicBell support mobile push notifications$q$, $q$Yes, MagicBell supports mobile push for iOS and Android in addition to web push, email, SMS, Slack, and in-app notifications.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$How is MagicBell priced$q$, $q$MagicBell is priced by monthly notification deliveries, with a free tier for up to 1,000 deliveries and paid plans starting at 249 dollars per month for 50,000 deliveries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$What are the main alternatives to MagicBell$q$, $q$Common alternatives include Courier, Novu, Knock, OneSignal, and Suprsend, all of which offer similar multi-channel notification infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$SaaS product notifications$q$, $q$Adding an in-app notification bell and email/push alerts for events like comments, mentions, and assignments.$q$, $q$Product and engineering teams at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Marketplace and collaboration app alerts$q$, $q$Notifying users across channels about new messages, orders, or status changes in real time.$q$, $q$Marketplace and collaboration platform developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Billing and account alerts$q$, $q$Sending transactional notifications for payment failures, plan changes, or security events.$q$, $q$Engineering teams building account and billing workflows$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Builder$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["1,000 deliveries per month","1 project","All integrations and channels","Unlimited team members"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Startup$q$, $q$$249/month$q$, $q$Monthly$q$, NULL, $q$["50,000 deliveries per month","Additional deliveries at $0.0025 each","5 projects included, extra projects at $99 each","All channels and integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$Enterprise$q$, $q$Custom$q$, $q$Annual/custom$q$, NULL, $q$["Unlimited deliveries","Unlimited projects","Integration support","Invoice billing and security review"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MagicBell is a notification API and inbox component built specifically for software products, rather than a marketing email tool. Instead of sending bulk campaigns, it is designed to be wired into an application's backend so that transactional and lifecycle events, such as a comment, a mention, a task assignment, or a billing alert, are pushed to end users across whichever channel they prefer.$q$, $q$The product centers on a pre-built notification inbox UI that can be dropped into a web or mobile app, combined with a backend API that developers call whenever an event happens. MagicBell then handles routing that event to email, push, SMS, Slack, or in-app display based on each user's saved preferences.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MagicBell's core feature set includes a customizable, embeddable notification inbox, multi-channel delivery (in-app, email, mobile push, web push, Slack, Microsoft Teams, and SMS), and a preference center that lets end users control which notifications they receive and on which channel.$q$, $q$Additional capabilities include notification templates with variables, delivery batching and digests to avoid overwhelming users, real-time updates over websockets, delivery and engagement analytics, and SDKs for React, React Native, Node.js, Ruby, Python, and Go that reduce integration time for engineering teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('683c4752-3d3c-49ed-8578-cbba9f8507d3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MagicBell uses usage-based pricing tied to monthly notification deliveries rather than contacts or seats. The free Builder plan covers 1,000 deliveries per month across all channels and integrations with unlimited team members, making it usable for early-stage products.$q$, $q$The Startup plan starts at 249 dollars per month for 50,000 deliveries, with overage priced per additional delivery, while the Enterprise tier removes delivery caps and adds security review, SSO, and invoice billing for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$One-script setup$q$, $q$A single install script configures the entire mail server stack on a fresh Ubuntu VPS.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Automatic TLS certificates$q$, $q$Requests and renews HTTPS/TLS certificates via Let's Encrypt without manual intervention.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$DNS and authentication automation$q$, $q$Configures SPF, DKIM, and DMARC records to improve outbound deliverability.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Webmail included$q$, $q$Ships with Roundcube for browser-based email access.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Contacts and calendar sync$q$, $q$CardDAV and CalDAV support via Nextcloud for syncing contacts and calendars to devices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Spam filtering$q$, $q$Built-in SpamAssassin-based filtering for incoming mail.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Multi-user, multi-domain support$q$, $q$Hosts mailboxes for multiple users and multiple domain names on one server.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Backup and monitoring tools$q$, $q$Includes automated backup routines and basic server health monitoring.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Single script dramatically simplifies self-hosted email setup$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Secure defaults reduce common misconfiguration risks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Includes webmail, contacts, and calendar sync out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Full ownership and control of email data and infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Requires comfort with the command line and basic server administration$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Limited flexibility compared to modular options like Mailcow or Mailu$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$No official commercial support or SLA since it is a community project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Running a reliable mail server long-term still requires ongoing maintenance and IP reputation management$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Single-server design means less built-in redundancy than managed email providers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$What is Mail-in-a-Box$q$, $q$Mail-in-a-Box is a free, open-source script that automatically configures a full self-hosted email server, including webmail, contacts, and calendar, on a plain Ubuntu VPS.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Is Mail-in-a-Box free$q$, $q$Yes, the software is free and released under a CC0 public-domain license; the only cost is the VPS hosting it runs on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Who created Mail-in-a-Box$q$, $q$Mail-in-a-Box was created in 2013 by developer Joshua Tauberer and is maintained as an open-source community project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$What operating system does Mail-in-a-Box require$q$, $q$Mail-in-a-Box is designed to run on Ubuntu LTS releases, with current versions targeting Ubuntu 22.04.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Does Mail-in-a-Box include webmail and calendar sync$q$, $q$Yes, it includes Roundcube for webmail and Nextcloud-based CardDAV/CalDAV support for contacts and calendar syncing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$How does Mail-in-a-Box compare to Mailcow$q$, $q$Mail-in-a-Box favors a simple, opinionated one-script setup, while Mailcow uses Docker containers and offers more modular configuration and a fuller groupware feature set.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Personal email independence$q$, $q$Running a private mail server for one or a few personal domains instead of relying on a third-party provider.$q$, $q$Privacy-conscious individuals and hobbyist sysadmins$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Small nonprofit or community group email$q$, $q$Hosting email for a small organization without paying per-mailbox fees to a commercial provider.$q$, $q$Small nonprofits and community organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Developer learning and experimentation$q$, $q$Standing up a real mail server to learn SMTP, DNS authentication, and mail administration hands-on.$q$, $q$Developers and students learning email infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full mail server stack","Webmail via Roundcube","Contacts and calendar sync","DNS and TLS automation","Runs on your own VPS (hosting cost not included)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mail-in-a-Box packages the standard open-source email stack, Postfix, Dovecot, spam filtering, DNS authentication, webmail, and contacts/calendar sync, into a single automated setup script that provisions a working mail server on a fresh Ubuntu VPS in a few hours.$q$, $q$Unlike modular self-hosted email projects that require assembling and configuring many components separately, Mail-in-a-Box is intentionally opinionated: it makes most configuration decisions for the user with secure, spam-resistant defaults, trading flexibility for a much lower setup and maintenance burden.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The project bundles SMTP and IMAP mail handling, automatic Let's Encrypt TLS certificates, DNS record configuration for SPF, DKIM, and DMARC, spam filtering, and a Roundcube webmail interface, all managed through a single web-based control panel.$q$, $q$It also includes CardDAV/CalDAV contact and calendar sync via Nextcloud, automated backups, basic monitoring and status checks, and support for hosting multiple users and multiple domains on one server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mail-in-a-Box itself is free and released under a CC0 public-domain license with no paid tier, no vendor, and no license fee of any kind.$q$, $q$The only recurring cost is the cloud VPS the software runs on, which typically ranges from a few dollars to around ten dollars per month depending on the hosting provider and server size chosen.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d082b33f-646c-4955-831f-c22ea77858a8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Drag-and-drop email builder$q$, $q$Visual editor plus custom-coded HTML template support for designing campaigns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Marketing automation journeys$q$, $q$Trigger-based automated email sequences responding to subscriber behavior and purchases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Audience segmentation$q$, $q$Tag and segment contacts by behavior, purchase history, and engagement for targeted sends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Landing pages and signup forms$q$, $q$Build standalone landing pages and popup/embedded forms to grow an email list.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$E-commerce integrations$q$, $q$Native connections to Shopify, WooCommerce, and other platforms for revenue tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$A/B testing$q$, $q$Test subject lines, content, and send times to optimize campaign performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Generative AI content tools$q$, $q$AI-assisted subject line and copy generation added under Intuit ownership.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Reporting and analytics$q$, $q$Dashboards tracking opens, clicks, revenue, and campaign performance over time.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Widely recognized brand with a large template and integration ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Free plan available for very small lists to get started$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$All-in-one suite covering email, landing pages, and light automation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Strong e-commerce integrations for Shopify and WooCommerce sellers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Backed by Intuit's resources and connections to other small-business tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Pricing scales quickly with contact count and has risen notably since the Intuit acquisition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Free plan limits have been repeatedly reduced, most recently in 2026$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Automation and segmentation depth trails specialists like ActiveCampaign or Klaviyo$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Higher-tier features like phone support and predictive segmentation are locked behind expensive plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Interface can feel complex for users who only need simple newsletter sending$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Is Mailchimp free to use$q$, $q$Mailchimp offers a free plan limited to 250 contacts and 500 emails per month, with a 250-email daily sending cap, but larger or more advanced use requires a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Who owns Mailchimp$q$, $q$Mailchimp is owned by Intuit, which completed its acquisition of the company in November 2021 for approximately 12 billion dollars.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Who founded Mailchimp$q$, $q$Mailchimp was founded in 2001 by Ben Chestnut and Mark Armstrong, with Dan Kurzius joining as a co-founder soon after.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$How does Mailchimp pricing work$q$, $q$Mailchimp prices its Essentials, Standard, and Premium plans based on both feature tier and the number of contacts in an account, so cost rises as a list grows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$What is the best Mailchimp alternative$q$, $q$Popular alternatives include Constant Contact, Klaviyo, ActiveCampaign, Brevo, and MailerLite, depending on whether the priority is e-commerce, automation depth, or price.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Does Mailchimp support marketing automation$q$, $q$Yes, Mailchimp offers automation journeys with branching logic triggered by subscriber behavior, though depth varies by plan tier.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Small business newsletters$q$, $q$Sending regular email newsletters and promotions to a growing customer list.$q$, $q$Solo entrepreneurs and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$E-commerce marketing automation$q$, $q$Triggering abandoned cart, post-purchase, and win-back emails tied to Shopify or WooCommerce stores.$q$, $q$E-commerce brands and online retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Multi-channel campaign management$q$, $q$Coordinating email, landing pages, and signup forms as part of a broader marketing funnel.$q$, $q$Marketing teams at mid-sized companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 250 contacts","500 emails/month, 250/day cap","1 seat, 1 audience","Basic templates and scheduling"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Essentials$q$, $q$From ~$13/month$q$, $q$Monthly or annual$q$, NULL, $q$["3 seats, 3 audiences","A/B testing","Custom-coded templates (create only)","Basic automation flows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Standard$q$, $q$From ~$20/month$q$, $q$Monthly or annual$q$, NULL, $q$["5 seats, 5 audiences","Up to 200 automation flows","Generative AI features","Predictive send-time features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$Premium$q$, $q$From ~$350/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited contacts and users","Unlimited audiences","Predictive segmentation","Phone and 24/7 priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailchimp is one of the best-known email marketing platforms in the world, having grown from a bootstrapped side project in 2001 into a multi-billion dollar marketing suite acquired by Intuit in 2021 for roughly 12 billion dollars.$q$, $q$Beyond email campaigns, the platform has expanded into a broader marketing hub covering landing pages, simple websites, audience/CRM management, and automation, aimed at helping small and mid-sized businesses run marketing without a dedicated technical team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mailchimp's core toolset includes a drag-and-drop email builder, customizable templates, A/B and multivariate testing, and automation journeys that trigger based on subscriber behavior such as purchases, signups, or website activity.$q$, $q$Since joining Intuit, the platform has added generative AI content assistance, predictive audience segmentation, and send-time optimization, alongside existing features like popup signup forms, landing pages, and e-commerce integrations with platforms such as Shopify and WooCommerce.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('453ae436-57ca-4b8a-8abd-3f36dcefa927', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailchimp offers a free plan capped at 250 contacts and 500 emails per month, with a daily sending limit of 250 emails, making it suitable mainly for very small lists or testing.$q$, $q$Paid plans, Essentials, Standard, and Premium, price by both feature tier and contact count, with Premium removing contact limits entirely and adding phone support, predictive segmentation, and dedicated onboarding for larger senders.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Docker-based deployment$q$, $q$Ships as Docker Compose services for portable, consistent installs across environments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Full mail server stack$q$, $q$Bundles Postfix, Dovecot, Rspamd, and ClamAV for mail transfer, access, spam, and virus filtering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$SOGo groupware and webmail$q$, $q$Includes webmail plus calendar, contacts, and task syncing via CalDAV/CardDAV.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Modern admin UI$q$, $q$Centralized web panel for managing domains, mailboxes, aliases, and quotas.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Strong deliverability defaults$q$, $q$Automatic DKIM, SPF, DMARC, DANE, and MTA-STS configuration to protect sender reputation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Two-factor authentication$q$, $q$Built-in 2FA support for admin and user accounts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$REST API$q$, $q$Enables automation and integration with external provisioning or management systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Multi-domain and per-domain delegation$q$, $q$Supports hosting many domains with delegated per-domain administration.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Includes full groupware (calendar, contacts, tasks), not just email$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Modern, actively maintained admin interface compared to older self-hosted options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Strong built-in security and deliverability defaults out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Docker-based architecture makes upgrades and component isolation cleaner$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Requires solid Docker and Linux administration knowledge to run reliably$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Higher resource requirements than lighter self-hosted mail options$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$No official free support channel beyond community forums and Telegram$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Initial setup and DNS configuration can be complex for beginners$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Self-hosting still requires ongoing IP reputation and maintenance work$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$What is mailcow$q$, $q$Mailcow is a free, open-source, Docker-based mail server and groupware suite that combines Postfix, Dovecot, Rspamd, and SOGo behind a modern admin panel.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Is mailcow free to use$q$, $q$Yes, mailcow is open source and free to run; optional paid support and managed hosting are available from third parties but not required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Does mailcow include webmail and calendar$q$, $q$Yes, mailcow includes SOGo for webmail along with calendar, contacts, and task syncing via CalDAV and CardDAV.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$What do I need to run mailcow$q$, $q$Mailcow requires a Linux server with Docker and Docker Compose installed, along with a domain name for DNS and TLS configuration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Who maintains mailcow$q$, $q$Mailcow is maintained by The Infrastructure Company GmbH, based in Willich, Germany, which also offers commercial support and hosting.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$How does mailcow compare to Mail-in-a-Box$q$, $q$Mailcow offers more modularity, groupware features, and a more polished admin UI, while Mail-in-a-Box favors a simpler single-script setup with fewer moving parts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Self-hosted business email and groupware$q$, $q$Replacing hosted suites like Google Workspace with a self-managed mail, calendar, and contacts platform.$q$, $q$Small businesses and privacy-focused organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Managed service provider email hosting$q$, $q$Running multi-tenant email hosting for multiple client domains with per-domain delegation.$q$, $q$MSPs and hosting providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Homelab and self-hosting enthusiasts$q$, $q$Running a personal or family mail server as part of a broader self-hosted infrastructure.$q$, $q$Self-hosting hobbyists and sysadmins$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Postfix/Dovecot/Rspamd/SOGo stack","Webmail, calendar, and contacts","Admin panel and REST API","Runs on your own Docker host (hosting cost not included)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailcow packages a full open-source email and groupware stack, mail transfer, IMAP, spam and virus filtering, webmail, calendar, and contacts, into a set of Docker containers managed through a single modern admin panel.$q$, $q$It targets administrators who want more feature depth and modularity than a one-script mail server while still avoiding the complexity of assembling each component from scratch, positioning it between minimal setups like Mail-in-a-Box and heavyweight suites like Zimbra.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The stack combines Postfix, Dovecot, Rspamd, ClamAV, and SOGo to deliver mail transfer, mailbox access, spam/virus filtering, and groupware (webmail, calendar, contacts, tasks) in one deployment.$q$, $q$Security and deliverability features include enforced TLS, DANE, MTA-STS, automatic Let's Encrypt certificates, outgoing DKIM signing, SPF/DMARC handling, anti-spoofing, greylisting, and malicious attachment blocking, all configurable through the web admin UI.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailcow is fully open source and free to run under its GPLv3 license, with no separate paid software tier for the core product.$q$, $q$Organizations that don't want to self-manage the Docker stack can pay for commercial support or managed hosting from mailcow's maintaining company or other providers, but this is optional rather than required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f9d56d4e-fc0b-4b1a-9ea8-231bd20b02d4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Multi-mode email editor$q$, $q$Drag-and-drop, custom HTML, and simplified rich-text editors for building campaigns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Marketing automation$q$, $q$Trigger-based workflows with branching logic for welcome series, abandoned cart, and re-engagement flows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Landing pages and websites$q$, $q$Built-in landing page and lightweight website builder alongside email tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Signup forms and pop-ups$q$, $q$Embedded and popup forms to grow subscriber lists directly on a site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$AI writing assistant$q$, $q$AI-generated subject lines and email copy suggestions built into the editor.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Digital products and bookings$q$, $q$Sell digital products or accept bookings directly through MailerLite campaigns and pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Dynamic content and personalization$q$, $q$Show different content blocks to different segments within the same campaign.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Preference center$q$, $q$Lets subscribers manage their own email frequency and topic preferences.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Clean, easy-to-use editor that suits non-technical users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Bundles website and landing page tools alongside email at no extra cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Free plan available for very small lists$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Digital product and booking features reduce need for extra tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Multilingual interface supports non-English-speaking users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Mid-2026 pricing changes raised costs by 10 to 30 percent across most tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Automation depth is lighter than specialists like ActiveCampaign$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Free plan API access does not support sending$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Deliverability support and dedicated IPs are reserved for higher tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Now owned by Vercom, adding a layer of corporate ownership to a previously independent brand$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Is MailerLite free$q$, $q$Yes, MailerLite offers a free plan for up to 250 active subscribers with 2,500 monthly emails and two user seats.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Who owns MailerLite$q$, $q$MailerLite was acquired by Vercom, a Polish communications technology company, in April 2022, though it still operates under its own brand.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$When was MailerLite founded$q$, $q$MailerLite was founded in 2010 by Ignas Rubezius in Vilnius, Lithuania, starting as a side project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Did MailerLite pricing change in 2026$q$, $q$Yes, in mid-2026 MailerLite renamed its Growing Business and Advanced plans to Comfort and Power and raised prices by roughly 10 to 30 percent across most subscriber tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Does MailerLite include a website builder$q$, $q$Yes, MailerLite includes landing page and lightweight website building tools alongside its email marketing features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$What is the best alternative to MailerLite$q$, $q$Common alternatives include Mailchimp, Brevo, ConvertKit (Kit), and ActiveCampaign, depending on whether the priority is price, automation depth, or creator-specific features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Creator newsletters$q$, $q$Sending regular newsletters and monetizing an audience through digital products.$q$, $q$Bloggers, creators, and solo entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Small e-commerce email marketing$q$, $q$Running automated abandoned cart and promotional campaigns for a small online store.$q$, $q$Small e-commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$All-in-one small business web presence$q$, $q$Using the bundled website and landing page builder alongside email campaigns instead of separate tools.$q$, $q$Small businesses without a dedicated website$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 250 active subscribers","2,500 monthly emails","2 user seats","Campaigns, automations, website, landing page, signup forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Comfort$q$, $q$From $12/month$q$, $q$Monthly or annual (10% discount annually)$q$, NULL, $q$["Scales with subscriber tier","3 user seats","50 active automations","10 websites/landing pages, AI writing assistant"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Power$q$, $q$From $25/month$q$, $q$Monthly or annual (10% discount annually)$q$, NULL, $q$["Unlimited monthly emails","Unlimited seats and automations","24/7 live chat support","Dedicated IP option"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["200,000+ subscribers","Dedicated success manager","Account audit and deliverability support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MailerLite is an email marketing platform built around a clean, minimalist campaign editor and a broader toolkit that includes automation, landing pages, websites, and signup forms, aimed primarily at solo creators and small businesses.$q$, $q$Founded in Lithuania in 2010 and acquired by Vercom in 2022, MailerLite has grown into a widely used alternative to larger platforms like Mailchimp, historically trading on simplicity and lower pricing, though its 2026 plan restructuring pushed prices closer to competitors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include drag-and-drop, HTML, and rich-text email editors, automation workflows with branching logic, subscriber segmentation, and A/B testing for subject lines and content.$q$, $q$The platform also bundles website and landing page builders, embedded and popup signup forms, an AI writing assistant, dynamic content blocks, and support for selling digital products and bookings directly through email campaigns.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb14d50a-e3a5-457e-8b21-c45cdda89d54', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MailerLite's free plan supports up to 250 active subscribers and 2,500 monthly emails with two user seats, making it usable for very early-stage lists.$q$, $q$Paid plans, renamed Comfort and Power in mid-2026, start at 12 dollars per month and scale by subscriber count, with Power offering unlimited sending and automations, and a custom-priced Enterprise tier available above 200,000 subscribers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Transactional email API and SMTP relay$q$, $q$RESTful API and SMTP relay for sending programmatic email from applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Email validation$q$, $q$Real-time and bulk address verification to reduce bounces before sending.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Deliverability optimization$q$, $q$Monitoring and tooling to help maintain sender reputation and inbox placement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Email rendering previews$q$, $q$Inspect emails across different clients and devices before sending, powered by Email on Acid.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Inbound routing and parsing$q$, $q$Receive and programmatically process incoming email through the API.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Webhooks and analytics$q$, $q$Track opens, clicks, bounces, and spam complaints via webhooks and dashboards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Dedicated IP pools$q$, $q$Optional dedicated sending IPs available on higher-tier plans for reputation control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$SAML SSO$q$, $q$Single sign-on support for teams on the Scale and Enterprise tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Mature, well-documented API with a long track record since 2010$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Built-in email validation reduces bounce rates and protects sender reputation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Flexible product suite covering sending, validation, and rendering checks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Usage-based pricing scales predictably with sending volume$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Backed by Sinch's broader communications infrastructure and reliability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Free tier is limited to 100 emails per day$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Pricing and features have shifted since becoming part of a larger public company$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Advanced features like SSO and dedicated IP pools require higher-cost plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Primarily built for developers, with less appeal for non-technical marketers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Support quality on lower tiers is more limited than on Scale/Enterprise plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$What is Mailgun used for$q$, $q$Mailgun is used by developers to send transactional email, such as password resets, receipts, and notifications, programmatically through an API or SMTP relay.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Is Mailgun free$q$, $q$Mailgun offers a free plan limited to 100 emails per day; paid plans start around 15 dollars per month for higher volumes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Who owns Mailgun now$q$, $q$Mailgun is owned by Sinch, a Swedish communications platform company, which acquired it along with Mailjet through the 2021 Pathwire acquisition.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$When was Mailgun founded$q$, $q$Mailgun was founded in 2010 by Ev Kontsevoy and Taylor Wakefield and went through Y Combinator in 2011.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Does Mailgun validate email addresses$q$, $q$Yes, Mailgun's Validate product offers real-time and bulk email address verification to help reduce bounces.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$What are the main alternatives to Mailgun$q$, $q$Common alternatives include SendGrid, Amazon SES, Postmark, SparkPost, and Mailjet.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Transactional email for SaaS apps$q$, $q$Sending password resets, receipts, and account notifications reliably from an application backend.$q$, $q$Software engineers and SaaS platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Marketplace and platform notifications$q$, $q$Delivering order confirmations and status updates programmatically at scale.$q$, $q$Marketplace and e-commerce platform developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Email deliverability monitoring$q$, $q$Using validation and inspection tools to maintain sender reputation for high-volume senders.$q$, $q$Technical teams managing large-scale email sending$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["100 emails/day","1 custom sending domain","RESTful API and SMTP relay","1 day log retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Basic$q$, $q$From $15/month$q$, $q$Monthly$q$, NULL, $q$["10,000 emails/month included","No daily email limit","1 custom sending domain","5 inbound routes"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Foundation$q$, $q$From $35/month$q$, $q$Monthly$q$, NULL, $q$["50,000 emails/month included","1,000 custom sending domains","Email template builder","5 days log retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Scale$q$, $q$From $90/month$q$, $q$Monthly$q$, NULL, $q$["100,000 emails/month included","SAML SSO","Dedicated IP pools","30 days log retention"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom volume pricing","Dedicated deliverability services","Priority support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailgun is a transactional email API built for developers, letting applications send, receive, and track email programmatically rather than through a marketing campaign interface.$q$, $q$Founded in 2010 and now owned by Sinch after passing through Rackspace and an independent spinout as Pathwire, Mailgun remains one of the longest-running API-first email providers, known for pairing sending infrastructure with deliverability and validation tooling.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mailgun's product suite includes Send for core API/SMTP email delivery, Validate for real-time and bulk address verification, Optimize for deliverability monitoring, and Inspect for previewing how emails render across different clients.$q$, $q$Additional capabilities include inbound email parsing and routing, detailed sending logs and webhooks, dedicated IP addresses, SAML SSO on higher tiers, and DKIM/SPF/DMARC configuration support to protect sender reputation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e42b88f9-4910-4f3d-aacc-b784e0b8f957', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailgun's free plan allows up to 100 emails per day with access to the core API and SMTP relay, one sending domain, and basic tracking and webhooks.$q$, $q$Paid plans scale by monthly email volume, starting around 15 dollars per month for 10,000 emails and rising through Foundation and Scale tiers that add features like template building, dedicated IP pools, and SSO, with custom Enterprise pricing for very high volumes.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$List moderation and subscription management$q$, $q$Configurable rules for who can post, subscribe, and moderate messages on a list.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Digest and individual delivery$q$, $q$Subscribers can receive messages individually or bundled into periodic digests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Web-based archive search$q$, $q$HyperKitty provides a searchable, browsable web archive of past list messages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Automatic bounce processing$q$, $q$Detects and handles bouncing addresses to keep list health intact.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$DMARC mitigation$q$, $q$Handles mail from strict DMARC-enforcing domains to avoid delivery failures on lists.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$REST API$q$, $q$Allows scripting and integration with external tools for automation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Postorius admin interface$q$, $q$Web-based panel for managing list settings, members, and moderation queues.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$MTA integration$q$, $q$Works alongside mail transfer agents like Postfix or Exim to process list mail.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Decades of maturity and battle-testing across countless open-source and institutional lists$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Fine-grained moderation and posting control suited to real list governance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Searchable web archives built in via HyperKitty$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Active ongoing maintenance and REST API for automation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Requires self-hosting and Linux/mail server administration knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Interface and workflow feel dated compared to modern newsletter platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Not designed for marketing-style campaigns, analytics, or design-heavy emails$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Migrating from Mailman 2 to Mailman 3 can require nontrivial effort$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$No commercial support channel from a central vendor$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$What is GNU Mailman used for$q$, $q$GNU Mailman is used to run traditional email mailing lists for discussion groups, announcements, and community communication with moderation and archiving.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Is Mailman free$q$, $q$Yes, Mailman is free and open-source software released under the GNU General Public License, with no license cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Who maintains GNU Mailman$q$, $q$Mailman is a community-maintained GNU Project with no company behind it; Barry Warsaw led development for many years and Abhilash Raj currently maintains it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$What is the difference between Mailman 2 and Mailman 3$q$, $q$Mailman 3, released in 2015, split the system into separate Core, Postorius (admin UI), and HyperKitty (web archive) components, replacing the older monolithic Mailman 2 and its Pipermail archiver.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Is GNU Mailman the same as email marketing software like Mailchimp$q$, $q$No, Mailman is designed for traditional discussion and announcement mailing lists with moderation and archiving, not for marketing campaigns, design templates, or analytics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$What are alternatives to GNU Mailman$q$, $q$Alternatives include other open-source list managers like Sympa and Majordomo, as well as modern platforms like Google Groups or Discourse for community-style communication.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Open-source project mailing lists$q$, $q$Running developer and user discussion lists for open-source software projects.$q$, $q$Open-source maintainers and communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Academic and institutional lists$q$, $q$Managing department, course, or organizational announcement and discussion lists.$q$, $q$Universities and research institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Nonprofit and association communication$q$, $q$Coordinating member discussions and announcements for professional or nonprofit groups.$q$, $q$Nonprofits and professional associations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Mailman Core message processing","Postorius web admin interface","HyperKitty searchable archive","Runs on your own server (hosting cost not included)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GNU Mailman is a free, open-source system for running traditional email mailing lists, handling subscriptions, moderation, digesting, and archiving for discussion and announcement lists.$q$, $q$With roots going back to the mid-1990s and a first public release in 1999, Mailman is one of the longest-running pieces of open-source mailing list infrastructure still actively maintained, now in its Mailman 3 generation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mailman 3 splits functionality into Mailman Core for message processing, Postorius for web-based list administration and subscriptions, and HyperKitty for searchable web archives of list history.$q$, $q$Additional features include configurable moderation and posting permission rules, automatic bounce handling, digest delivery options, DMARC mitigation for strict sending domains, and a REST API for scripting and integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailman is entirely free and open source under the GNU General Public License, with no vendor, no license fee, and no paid tier for the software itself.$q$, $q$The only cost is the infrastructure needed to self-host it, or a fee if using a third-party managed Mailman hosting provider instead of running it in-house.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('09b6e7a8-b810-4a31-9ecf-e4e0719bc76c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Full-text search and filtering$q$, $q$Search archived email content and attachments quickly across large mail volumes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Tamper-evident archiving$q$, $q$Stores messages in a way designed to prove they have not been altered after archiving.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Retention policy enforcement$q$, $q$Configurable rules to retain email records for required compliance periods.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Scalable indexing and storage$q$, $q$Optimized to handle archives containing millions of emails efficiently.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$AI-powered natural language search (Enterprise)$q$, $q$Allows plain-English queries that are translated into precise archive searches.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$PII and phishing detection (Enterprise)$q$, $q$Built-in detection of personally identifiable information and machine-learning-based phishing identification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$DLP policy support (Enterprise)$q$, $q$Data loss prevention policies to flag or restrict sensitive content in the archive.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Encrypted storage with digital fingerprinting (Enterprise)$q$, $q$Encrypts archived messages and verifies integrity with digital fingerprints.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Genuinely free and open-source core product, unusual for email archiving software$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Scales to large mail volumes with efficient search and indexing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Enterprise edition adds meaningful compliance features like PII and phishing detection$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$30-day free trial available for Enterprise features before committing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Clear upgrade path from self-hosted open source to supported Enterprise edition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Open Source Edition has only community support, no guaranteed response time$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Enterprise pricing and licensing model can be complex to evaluate for smaller organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Requires self-hosting infrastructure and mail server integration knowledge$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$AI-powered search and advanced security features are Enterprise-only$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Less brand recognition than large commercial archiving vendors like Mimecast or Proofpoint$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$What is mailpiler (Piler) used for$q$, $q$Piler is used for archiving incoming and outgoing email so organizations can search, retain, and retrieve records for compliance and legal e-discovery purposes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Is Piler free$q$, $q$The Open Source Edition of Piler is free to self-host; a paid Enterprise Edition adds AI search, advanced security features, and professional support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Who maintains the Piler project$q$, $q$Piler is maintained primarily by a developer known as jsuto, with the core source code publicly available on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$What does the Enterprise Edition of Piler add$q$, $q$The Enterprise Edition adds AI-powered natural-language search, PII detection, phishing detection, DLP policy support, and encrypted storage with digital fingerprinting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$How much does Piler Enterprise cost$q$, $q$Piler Enterprise licensing has been reported to start around 400 to 2,000 euros for the first year with renewals from about 150 euros per year, plus a 30-day free trial.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$What are alternatives to Piler for email archiving$q$, $q$Common alternatives include Mimecast, Barracuda Message Archiver, Proofpoint Archiving, and Global Relay, along with other self-hosted archiving tools.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Regulatory compliance archiving$q$, $q$Retaining and proving the integrity of email records for regulated industries like finance and healthcare.$q$, $q$Compliance and legal teams in regulated industries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Legal e-discovery$q$, $q$Searching historical email archives to produce records requested during litigation or investigations.$q$, $q$Legal departments and e-discovery specialists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Self-hosted email backup and search$q$, $q$Running a free, self-managed archive of company email for internal search and record-keeping.$q$, $q$IT administrators at cost-conscious organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Open Source Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full-text search","Tamper-evident archiving","Retention policy enforcement","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$Enterprise Edition$q$, $q$From ~400 EUR first year (renewals from ~150 EUR/year)$q$, $q$Annual license$q$, NULL, $q$["AI-powered natural language search","PII and phishing detection","DLP policy support","Encrypted storage with digital fingerprinting","Professional support, 30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Piler, published as mailpiler, is an open-source email archiving system that captures and indexes email traffic so organizations can search, retain, and produce historical email records for compliance and legal purposes.$q$, $q$It is available as a free, self-hosted Open Source Edition, and as a paid Enterprise Edition sold separately through mailpiler.com that adds AI-powered search, security, and professional support for organizations with stricter compliance requirements.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The open-source core provides full-text search across archived email and attachments, tamper-evident storage, retention policy enforcement, and scalable indexing designed to handle archives of millions of messages.$q$, $q$The Enterprise Edition adds natural-language AI search, built-in PII detection, machine-learning-based phishing detection, data loss prevention policy support, and encrypted storage with digital fingerprinting to verify message integrity for audits and legal discovery.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Open Source Edition of Piler is completely free, with community support available through GitHub and forums, making it accessible to any organization willing to self-host and self-manage the archive.$q$, $q$The Enterprise Edition is licensed commercially, with a base license reported around 400 to 2,000 euros for the first year covering one server, renewals from roughly 150 euros per year, and a 30-day free trial that includes all Enterprise features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4dbc9062-8847-4d09-ad79-21686e6afd30', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
